import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Issue 2133 - Endless loop in wrapping binary expression after elvis operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                  $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                  $EOL_CHAR
            val foo =
                bar ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // This test case only checks BinaryExpressionWrappingRule in isolation. 
        // In isolation, it should probably just wrap after ?:
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Issue 2133 - Endless loop in wrapping binary expression after elvis operator (including ChainWrappingRule)`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                  $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // If ChainWrappingRule is added, it should not loop.
        // The expected formatted code depends on which rule "wins" or how they collaborate.
        // ChainWrappingRule wants ?: at the start of the line.
        // BinaryExpressionWrappingRule wants to wrap when the line is too long.
        binaryExpressionWrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .setMaxLineLength()
            .isFormattedAs(
                """
                // $MAX_LINE_LENGTH_MARKER                                  $EOL_CHAR
                val foo =
                    bar
                        ?: throw UnsupportedOperationException(
                            "xxxxxxxxxxx"
                        )
                """.trimIndent()
            )
    }
}
"}

